}`;

  step3Code = `<!-- Simple translation -->
<h1>{{ 'greeting' | ngccI18n }}</h1>

<!-- With parameters -->
<p>{{ 'welcome' | ngccI18n: { name: userName } }}</p>

<!-- Multiple parameters -->
