    provideNgccI18n({
      defaultLanguage: 'en',
      fallbackLanguage: 'en',
      loader: new HttpNgccI18nLoader('/assets/i18n'),
    }),
  ],
});
\`\`\`

2. **Create translation files in \`public/assets/i18n/\`:**
   - en.json
   - fr.json
   - es.json

3. **Use in templates:**
\`\`\`html
{{ 'greeting' | ngccI18n }}
